import pymongo
from pymongo.errors import PyMongoError

def execute_server_side_javascript_query(collection_name, javascript_expression, projection=None, db_name='mydatabase', host='localhost', port=27017):
    """
    Executes a server-side JavaScript query using the $where operator in MongoDB.

    Args:
        collection_name (str): The name of the collection to query.
        javascript_expression (str): The JavaScript expression string to be used
                                     with the $where operator for filtering.
                                     This expression should evaluate to a boolean.
        projection (dict, optional): A dictionary specifying the fields to include
                                     or exclude in the result documents.
                                     Example: {"field_name": 1, "_id": 0}. Defaults to None,
                                     which means all fields are returned.
        db_name (str): The name of the database. Defaults to 'mydatabase'.
        host (str): The MongoDB host. Defaults to 'localhost'.
        port (int): The MongoDB port. Defaults to 27017.

    Returns:
        list: A list of dictionaries, where each dictionary represents a document
              matching the query, or an empty list if an error occurs or no documents match.
    """
    client = None
    try:
        client = pymongo.MongoClient(host, port)
        db = client[db_name]
        collection = db[collection_name]

        query = {"$where": javascript_expression}

        if projection:
            results = list(collection.find(query, projection))
        else:
            results = list(collection.find(query))

        return results

    except pymongo.errors.ConnectionFailure as e:
        print(f"MongoDB connection failed: {e}")
        return []
    except pymongo.errors.OperationFailure as e:
        print(f"MongoDB operation failed (likely server-side JS error or invalid expression): {e}")
        # Consider logging the full error for debugging server-side JS
        return []
    except PyMongoError as e:
        print(f"An unexpected PyMongo error occurred: {e}")
        return []
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return []
    finally:
        if client:
            client.close()

